// resourceIDFieldOverrides projects per-resource IDField (set by the profiler
// from x-resource-id or response-schema fallback) into a runtime lookup map.
// UpsertBatch consults this first so the templated path wins over the
// generic fallback list. Empty when no resource declared an override; the
// runtime fallback list still applies.
//
// Includes both flat resources and dependent (parent-child) resources so a
// child path-item annotated with x-resource-id resolves the same as a flat
// path-item.
var resourceIDFieldOverrides = map[string]string{
	"boards":          "id",
	"boards_groups":   "id",
	"boards_members":  "id",
	"connectors":      "id",
	"items":           "id",
	"tags":            "id",
	"v2_experimental": "id",
}

// genericIDFieldFallbacks is the runtime safety net for resources that did
// NOT receive a templated IDField. API-specific names belong in spec
// annotations (x-resource-id), not this list.
var genericIDFieldFallbacks = []string{"id", "ID", "name", "uuid", "slug", "key", "code", "uid"}

// UpsertBatch inserts or replaces multiple records in a single transaction
// and returns (stored, extractFailures, err). stored counts rows actually
// landed; extractFailures counts items that survived JSON unmarshal but had
// no extractable primary key (templated IDField AND generic fallback both
// missed). callers (sync.go.tmpl) compare these against len(items) to emit
// the per-item primary_key_unresolved warning and the F4b
// stored_count_zero_after_extraction probe.
//
// For resource types that have a domain-specific typed table, the per-item
// generic insert is followed by a dispatch to the matching upsert<Pascal>Tx
// inside the same transaction. Without that dispatch, paginated syncs would
// only populate the generic resources table — typed tables (and indexed
// columns like parent_id added by dependent-resource sync) would stay empty.
func (s *Store) UpsertBatch(resourceType string, items []json.RawMessage) (int, int, error) {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return 0, 0, fmt.Errorf("starting batch transaction: %w", err)
	}
	defer tx.Rollback()

	var stored, skippedCount, extractFailures int
	for _, item := range items {
		var obj map[string]any
		if err := json.Unmarshal(item, &obj); err != nil {
			skippedCount++
			continue
		}
		// Templated IDField wins; generic fallback list runs second when
		// the override is empty OR the override field is absent on this
		// particular item (response shape mismatches happen even when the
		// spec declares x-resource-id).
		var id string
		if override, ok := resourceIDFieldOverrides[resourceType]; ok && override != "" {
			if v := lookupFieldValue(obj, override); v != nil {
				s := fmt.Sprintf("%v", v)
				if s != "" && s != "<nil>" {
					id = s
				}
			}
		}
		if id == "" {
			for _, key := range genericIDFieldFallbacks {
				if v := lookupFieldValue(obj, key); v != nil {
					s := fmt.Sprintf("%v", v)
					if s != "" && s != "<nil>" {
						id = s
						break
					}
				}
			}
		}
		if id == "" {
			skippedCount++
			extractFailures++
			continue
		}

		if err := s.upsertGenericResourceTx(tx, resourceType, id, item); err != nil {
			return 0, extractFailures, fmt.Errorf("upserting %s/%s: %w", resourceType, id, err)
		}

		switch resourceType {
		case "audit":
			if err := s.upsertAuditTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "boards":
			if err := s.upsertBoardsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "app_cards":
			if err := s.upsertAppCardsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "cards":
			if err := s.upsertCardsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "connectors":
			if err := s.upsertConnectorsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "docs":
			if err := s.upsertDocsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "documents":
			if err := s.upsertDocumentsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "embeds":
			if err := s.upsertEmbedsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "frames":
			if err := s.upsertFramesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "boards_groups":
			if err := s.upsertBoardsGroupsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "images":
			if err := s.upsertImagesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "items":
			if err := s.upsertItemsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "boards_members":
			if err := s.upsertBoardsMembersTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "shapes":
			if err := s.upsertShapesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "sticky_notes":
			if err := s.upsertStickyNotesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "tags":
			if err := s.upsertTagsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "texts":
			if err := s.upsertTextsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "groups":
			if err := s.upsertGroupsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "oauth_token":
			if err := s.upsertOauthTokenTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "orgs":
			if err := s.upsertOrgsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "ai_interaction_logs":
			if err := s.upsertAiInteractionLogsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "orgs_boards":
			if err := s.upsertOrgsBoardsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "cases":
			if err := s.upsertCasesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "content_logs":
			if err := s.upsertContentLogsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "data_classification_settings":
			if err := s.upsertDataClassificationSettingsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "default_teams_settings":
			if err := s.upsertDefaultTeamsSettingsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "orgs_groups":
			if err := s.upsertOrgsGroupsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "orgs_members":
			if err := s.upsertOrgsMembersTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "projects":
			if err := s.upsertProjectsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "teams":
			if err := s.upsertTeamsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "resource_types":
			if err := s.upsertResourceTypesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "schemas":
			if err := s.upsertSchemasTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "service_provider_config":
			if err := s.upsertServiceProviderConfigTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "users":
			if err := s.upsertUsersTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "v2_experimental":
			if err := s.upsertV2ExperimentalTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		}
		stored++
	}

	// Warn when most items in a batch lack an extractable ID — this likely
	// means the API uses a primary key field we don't recognize yet.
	if skippedCount > 0 && len(items) > 0 && skippedCount*2 > len(items) {
		fmt.Fprintf(os.Stderr, "warning: %d/%d %s items skipped (no extractable ID field found)\n", skippedCount, len(items), resourceType)
	}

	if err := tx.Commit(); err != nil {
		return 0, extractFailures, err
	}
	return stored, extractFailures, nil
}

// SearchBoards searches the boards_fts index with optional filters.
func (s *Store) SearchBoards(query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := s.db.Query(
		`SELECT t.data FROM boards t
		 JOIN boards_fts ON boards_fts.rowid = t.rowid
		 WHERE boards_fts MATCH ?
		 ORDER BY rank LIMIT ?`,
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

